import { describe, expect, it, vi } from "vitest";
import { findMissingCoverage, parseUpdateAgentLabelsResult, parseVerdict, persistReplayLabels, toMcpLabels, } from "./persistReplayLabels.js";
const A = "11111111-1111-4111-8111-111111111111";
const B = "22222222-2222-4222-8222-222222222222";
const C = "33333333-3333-4333-8333-333333333333";
const TRUN = "44444444-4444-4444-8444-444444444444";
function fakeClient(responses) {
    const calls = [];
    let i = 0;
    return {
        calls,
        serviceUrl: "https://bitfab.test",
        ensureSession: vi.fn(async () => { }),
        call: vi.fn(async (_name, args) => {
            calls.push(args);
            const res = responses[Math.min(i, responses.length - 1)];
            i += 1;
            // When a test does not pin the text, synthesise the real server's
            // effective-label output, keyed by whichever id the label carries
            // (originalTraceId in lineage mode, or its deprecated sourceTraceId alias;
            // traceId in direct mode). This is what persistReplayLabels reads back to
            // verify persistence.
            const text = res.text ??
                [
                    "Update complete: ok.",
                    ...args.labels.map((label) => {
                        const id = (label.originalTraceId ??
                            label.sourceTraceId ??
                            label.traceId);
                        const effective = label.skip === true ? "skipped" : label.label ? "PASS" : "FAIL";
                        const action = label.skip === true ? "skipped" : "set";
                        return `- ${id}: ${action}; effective ${effective}`;
                    }),
                ].join("\n");
            return {
                content: [{ type: "text", text }],
                isError: res.isError ?? false,
            };
        }),
    };
}
describe("parseVerdict", () => {
    it("accepts a verdict with label + annotation", () => {
        expect(parseVerdict({ originalTraceId: A, label: true, annotation: "good" }, "originalTraceId")).toEqual({ kind: "verdict", id: A, label: true, annotation: "good" });
    });
    it("accepts a skip", () => {
        expect(parseVerdict({ originalTraceId: A, skip: true }, "originalTraceId")).toEqual({
            kind: "skip",
            id: A,
        });
    });
    it("reads the direct traceId key when idKind is traceId", () => {
        expect(parseVerdict({ traceId: A, label: false, annotation: "regressed" }, "traceId")).toEqual({ kind: "verdict", id: A, label: false, annotation: "regressed" });
    });
    it("accepts the deprecated sourceTraceId alias in lineage mode", () => {
        expect(parseVerdict({ sourceTraceId: A, label: true, annotation: "older item file" }, "originalTraceId")).toEqual({
            kind: "verdict",
            id: A,
            label: true,
            annotation: "older item file",
        });
    });
    it("prefers originalTraceId when both the canonical key and the alias are present", () => {
        expect(parseVerdict({ originalTraceId: A, sourceTraceId: B, label: true, annotation: "x" }, "originalTraceId")).toEqual({ kind: "verdict", id: A, label: true, annotation: "x" });
    });
    it("rejects missing id under the active idKind", () => {
        expect(parseVerdict({ label: true, annotation: "x" }, "originalTraceId")).toMatchObject({
            error: expect.stringMatching(/originalTraceId/),
        });
        // A traceId present but idKind is originalTraceId is still missing.
        expect(parseVerdict({ traceId: A, label: true, annotation: "x" }, "originalTraceId")).toMatchObject({ error: expect.stringMatching(/originalTraceId/) });
    });
    it("rejects non-skip entry missing label", () => {
        expect(parseVerdict({ originalTraceId: A, annotation: "x" }, "originalTraceId")).toMatchObject({
            error: expect.stringMatching(/label/),
        });
    });
    it("rejects non-skip entry missing annotation", () => {
        expect(parseVerdict({ originalTraceId: A, label: true }, "originalTraceId")).toMatchObject({
            error: expect.stringMatching(/annotation/),
        });
    });
    it("rejects non-object input", () => {
        expect(parseVerdict("oops", "originalTraceId")).toMatchObject({
            error: expect.stringMatching(/object/),
        });
    });
    it("accepts a verdict with optional confidence", () => {
        expect(parseVerdict({
            originalTraceId: A,
            label: true,
            annotation: "good",
            confidence: "High",
        }, "originalTraceId")).toEqual({
            kind: "verdict",
            id: A,
            label: true,
            annotation: "good",
            confidence: "High",
        });
    });
    it("rejects a verdict with an invalid confidence value", () => {
        expect(parseVerdict({
            originalTraceId: A,
            label: true,
            annotation: "x",
            confidence: "kinda-sure",
        }, "originalTraceId")).toMatchObject({
            error: expect.stringMatching(/confidence/),
        });
    });
    it("ignores confidence on a skip entry (no field surfaced)", () => {
        expect(parseVerdict({ originalTraceId: A, skip: true, confidence: "Low" }, "originalTraceId")).toEqual({ kind: "skip", id: A });
    });
});
describe("parseUpdateAgentLabelsResult", () => {
    it("extracts effective label states from agent-readable update output", () => {
        expect(parseUpdateAgentLabelsResult(`Update complete: set 3 verdict(s).
- ${A}: set; effective PASS
- ${B}: set; effective FAIL
- ${C}: skipped; effective skipped`)).toEqual(new Map([
            [A, "PASS"],
            [B, "FAIL"],
            [C, "skipped"],
        ]));
    });
});
describe("findMissingCoverage", () => {
    const verdicts = [
        { kind: "verdict", id: A, label: true, annotation: "x" },
        { kind: "skip", id: B },
    ];
    it("returns empty when every expected ID is verdicted or skipped", () => {
        expect(findMissingCoverage([A, B], verdicts)).toEqual([]);
    });
    it("returns the gap when some expected IDs are missing", () => {
        expect(findMissingCoverage([A, B, C], verdicts)).toEqual([C]);
    });
    it("returns the full expected list when nothing is verdicted", () => {
        expect(findMissingCoverage([A, B], [])).toEqual([A, B]);
    });
});
describe("toMcpLabels", () => {
    it("transforms verdicts and skips into the originalTraceId MCP payload shape", () => {
        expect(toMcpLabels([
            { kind: "verdict", id: A, label: true, annotation: "x" },
            { kind: "skip", id: B },
        ], "originalTraceId")).toEqual([
            { originalTraceId: A, sourceTraceId: A, label: true, annotation: "x" },
            { originalTraceId: B, sourceTraceId: B, skip: true },
        ]);
    });
    it("keys the payload by traceId in direct mode", () => {
        expect(toMcpLabels([
            { kind: "verdict", id: A, label: true, annotation: "x" },
            { kind: "skip", id: B },
        ], "traceId")).toEqual([
            { traceId: A, label: true, annotation: "x" },
            { traceId: B, skip: true },
        ]);
    });
    it("passes confidence through to the MCP payload when present", () => {
        expect(toMcpLabels([
            {
                kind: "verdict",
                id: A,
                label: true,
                annotation: "x",
                confidence: "Medium",
            },
        ], "originalTraceId")).toEqual([
            {
                originalTraceId: A,
                sourceTraceId: A,
                label: true,
                annotation: "x",
                confidence: "Medium",
            },
        ]);
    });
    it("omits confidence from the MCP payload when not present", () => {
        expect(toMcpLabels([{ kind: "verdict", id: A, label: true, annotation: "x" }], "originalTraceId")).toEqual([
            { originalTraceId: A, sourceTraceId: A, label: true, annotation: "x" },
        ]);
    });
});
describe("persistReplayLabels (lineage mode)", () => {
    it("returns invalid-input when expectedOriginalTraceIds is empty", async () => {
        const client = fakeClient([]);
        const result = await persistReplayLabels({
            client,
            rawInput: {
                testRunId: TRUN,
                expectedOriginalTraceIds: [],
                verdicts: [{ originalTraceId: A, skip: true }],
            },
        });
        expect(result.status).toBe("invalid-input");
        expect(client.call).not.toHaveBeenCalled();
    });
    it("returns invalid-input when testRunId is missing", async () => {
        const client = fakeClient([]);
        const result = await persistReplayLabels({
            client,
            rawInput: {
                expectedOriginalTraceIds: [A],
                verdicts: [{ originalTraceId: A, label: true, annotation: "x" }],
            },
        });
        expect(result.status).toBe("invalid-input");
        if (result.status === "invalid-input") {
            expect(result.message).toMatch(/testRunId/);
        }
        expect(client.call).not.toHaveBeenCalled();
    });
    it("returns missing-coverage and skips MCP when expected IDs are not all verdicted", async () => {
        const client = fakeClient([]);
        const result = await persistReplayLabels({
            client,
            rawInput: {
                testRunId: TRUN,
                expectedOriginalTraceIds: [A, B, C],
                verdicts: [{ originalTraceId: A, label: true, annotation: "x" }],
            },
        });
        expect(result).toEqual({
            status: "missing-coverage",
            idKind: "originalTraceId",
            missingIds: [B, C],
            providedIds: [A],
        });
        expect(client.call).not.toHaveBeenCalled();
    });
    it("returns invalid-input when a verdict entry is malformed", async () => {
        const client = fakeClient([]);
        const result = await persistReplayLabels({
            client,
            rawInput: {
                testRunId: TRUN,
                expectedOriginalTraceIds: [A],
                verdicts: [{ originalTraceId: A, label: true }],
            },
        });
        expect(result.status).toBe("invalid-input");
        expect(client.call).not.toHaveBeenCalled();
    });
    it("returns invalid-input when verdicts contain duplicate originalTraceIds", async () => {
        const client = fakeClient([]);
        const result = await persistReplayLabels({
            client,
            rawInput: {
                testRunId: TRUN,
                expectedOriginalTraceIds: [A, B],
                verdicts: [
                    { originalTraceId: A, label: true, annotation: "first" },
                    { originalTraceId: B, label: false, annotation: "second" },
                    {
                        originalTraceId: A,
                        label: false,
                        annotation: "conflicting duplicate",
                    },
                ],
            },
        });
        expect(result.status).toBe("invalid-input");
        if (result.status === "invalid-input") {
            expect(result.message).toMatch(new RegExp(`duplicate.*${A}`));
        }
        expect(client.call).not.toHaveBeenCalled();
    });
    it("persists all verdicts in one batch, sends testRunId, and reports counts", async () => {
        const client = fakeClient([{}]);
        const result = await persistReplayLabels({
            client,
            rawInput: {
                testRunId: TRUN,
                expectedOriginalTraceIds: [A, B, C],
                verdicts: [
                    { originalTraceId: A, label: true, annotation: "now passes" },
                    { originalTraceId: B, label: false, annotation: "still failing" },
                    { originalTraceId: C, skip: true },
                ],
            },
        });
        expect(result).toEqual({
            status: "ok",
            idKind: "originalTraceId",
            persistedIds: [A, B, C],
            passCount: 1,
            failCount: 1,
            skipCount: 1,
        });
        expect(client.call).toHaveBeenCalledTimes(1);
        expect(client.calls[0]).toEqual({
            testRunId: TRUN,
            labels: [
                {
                    originalTraceId: A,
                    sourceTraceId: A,
                    label: true,
                    annotation: "now passes",
                },
                {
                    originalTraceId: B,
                    sourceTraceId: B,
                    label: false,
                    annotation: "still failing",
                },
                { originalTraceId: C, sourceTraceId: C, skip: true },
            ],
        });
    });
    it("accepts an older item file keyed by the deprecated expectedSourceTraceIds/sourceTraceId aliases", async () => {
        const client = fakeClient([{}]);
        const result = await persistReplayLabels({
            client,
            rawInput: {
                testRunId: TRUN,
                expectedSourceTraceIds: [A, B],
                verdicts: [
                    { sourceTraceId: A, label: true, annotation: "now passes" },
                    { sourceTraceId: B, skip: true },
                ],
            },
        });
        expect(result).toEqual({
            status: "ok",
            idKind: "originalTraceId",
            persistedIds: [A, B],
            passCount: 1,
            failCount: 0,
            skipCount: 1,
        });
        // The MCP payload is keyed by the canonical originalTraceId even when the
        // input file used the deprecated alias.
        expect(client.calls[0]).toEqual({
            testRunId: TRUN,
            labels: [
                {
                    originalTraceId: A,
                    sourceTraceId: A,
                    label: true,
                    annotation: "now passes",
                },
                { originalTraceId: B, sourceTraceId: B, skip: true },
            ],
        });
    });
    it("batches into multiple MCP calls when more than 50 verdicts", async () => {
        const ids = Array.from({ length: 60 }, (_, i) => `00000000-0000-4000-8000-${String(i).padStart(12, "0")}`);
        const verdicts = ids.map((id) => ({
            originalTraceId: id,
            label: true,
            annotation: "pass",
        }));
        const client = fakeClient([{}, {}]);
        const result = await persistReplayLabels({
            client,
            rawInput: { testRunId: TRUN, expectedOriginalTraceIds: ids, verdicts },
        });
        expect(result.status).toBe("ok");
        expect(client.call).toHaveBeenCalledTimes(2);
        expect(client.calls[0].labels.length).toBe(50);
        expect(client.calls[1].labels.length).toBe(10);
    });
    it("returns mcp-error with partialIds when a mid-batch call fails", async () => {
        const ids = Array.from({ length: 60 }, (_, i) => `00000000-0000-4000-8000-${String(i).padStart(12, "0")}`);
        const verdicts = ids.map((id) => ({
            originalTraceId: id,
            label: true,
            annotation: "pass",
        }));
        const client = fakeClient([
            {},
            { text: "Bitfab API error (500)", isError: true },
        ]);
        const result = await persistReplayLabels({
            client,
            rawInput: { testRunId: TRUN, expectedOriginalTraceIds: ids, verdicts },
        });
        expect(result.status).toBe("mcp-error");
        if (result.status === "mcp-error") {
            expect(result.idKind).toBe("originalTraceId");
            expect(result.partialIds.length).toBe(50);
            expect(result.message).toMatch(/500/);
        }
    });
    it("returns mcp-error when the server reports no replay trace for an original trace", async () => {
        const client = fakeClient([
            {
                text: `No replay trace found for original trace(s) in test run ${TRUN}: ${B}`,
            },
        ]);
        const result = await persistReplayLabels({
            client,
            rawInput: {
                testRunId: TRUN,
                expectedOriginalTraceIds: [A, B],
                verdicts: [
                    { originalTraceId: A, label: true, annotation: "pass" },
                    { originalTraceId: B, label: false, annotation: "fail" },
                ],
            },
        });
        expect(result.status).toBe("mcp-error");
        if (result.status === "mcp-error") {
            expect(result.message).toContain("No replay trace found for original trace");
            expect(result.partialIds).toEqual([]);
        }
    });
    it("returns mcp-error on the older server wording ('for source trace(s)') too", async () => {
        const client = fakeClient([
            {
                text: `No replay trace found for source trace(s) in test run ${TRUN}: ${B}`,
            },
        ]);
        const result = await persistReplayLabels({
            client,
            rawInput: {
                testRunId: TRUN,
                expectedOriginalTraceIds: [A, B],
                verdicts: [
                    { originalTraceId: A, label: true, annotation: "pass" },
                    { originalTraceId: B, label: false, annotation: "fail" },
                ],
            },
        });
        expect(result.status).toBe("mcp-error");
    });
    it("returns verification-failed when the readable write result does not show the written label", async () => {
        const client = fakeClient([
            {
                text: `Update complete: set 1 verdict(s).
- ${A}: set; effective unlabeled`,
            },
        ]);
        const result = await persistReplayLabels({
            client,
            rawInput: {
                testRunId: TRUN,
                expectedOriginalTraceIds: [A],
                verdicts: [{ originalTraceId: A, label: true, annotation: "pass" }],
            },
        });
        expect(result.status).toBe("verification-failed");
        if (result.status === "verification-failed") {
            expect(result.idKind).toBe("originalTraceId");
            expect(result.mismatchedIds).toEqual([
                { id: A, expected: "PASS", actual: "unlabeled" },
            ]);
        }
    });
    it("returns verification-failed when update_agent_labels omits effective labels", async () => {
        const client = fakeClient([{ text: "Update complete: set 1 verdict(s)" }]);
        const result = await persistReplayLabels({
            client,
            rawInput: {
                testRunId: TRUN,
                expectedOriginalTraceIds: [A],
                verdicts: [{ originalTraceId: A, skip: true }],
            },
        });
        expect(result.status).toBe("verification-failed");
        if (result.status === "verification-failed") {
            expect(result.missingIds).toEqual([A]);
            expect(result.verifiedIds).toEqual([]);
            expect(result.message).toContain("effective label lines");
        }
    });
    it("ignores extra fields on input objects", async () => {
        const client = fakeClient([{}]);
        const result = await persistReplayLabels({
            client,
            rawInput: {
                testRunId: TRUN,
                expectedOriginalTraceIds: [A, B],
                verdicts: [
                    {
                        originalTraceId: A,
                        label: true,
                        annotation: "x",
                        extra: "ignored",
                    },
                    { originalTraceId: B, skip: true, alsoExtra: 42 },
                ],
                somethingUnrelated: true,
            },
        });
        expect(result.status).toBe("ok");
    });
});
describe("persistReplayLabels (direct traceId mode)", () => {
    it("accepts the pre-lineage file shape and keys labels by traceId, no testRunId", async () => {
        const client = fakeClient([{}]);
        const result = await persistReplayLabels({
            client,
            rawInput: {
                expectedTraceIds: [A, B, C],
                verdicts: [
                    { traceId: A, label: true, annotation: "now passes" },
                    { traceId: B, label: false, annotation: "still failing" },
                    { traceId: C, skip: true },
                ],
            },
        });
        expect(result).toEqual({
            status: "ok",
            idKind: "traceId",
            persistedIds: [A, B, C],
            passCount: 1,
            failCount: 1,
            skipCount: 1,
        });
        expect(client.call).toHaveBeenCalledTimes(1);
        // No testRunId is sent in direct mode, and labels carry traceId.
        expect(client.calls[0]).toEqual({
            labels: [
                { traceId: A, label: true, annotation: "now passes" },
                { traceId: B, label: false, annotation: "still failing" },
                { traceId: C, skip: true },
            ],
        });
    });
    it("returns missing-coverage keyed by traceId", async () => {
        const client = fakeClient([]);
        const result = await persistReplayLabels({
            client,
            rawInput: {
                expectedTraceIds: [A, B],
                verdicts: [{ traceId: A, label: true, annotation: "x" }],
            },
        });
        expect(result).toEqual({
            status: "missing-coverage",
            idKind: "traceId",
            missingIds: [B],
            providedIds: [A],
        });
        expect(client.call).not.toHaveBeenCalled();
    });
    it("returns mcp-error when the server rejects invalid trace IDs", async () => {
        const client = fakeClient([
            {
                text: "None of the provided trace IDs belong to this organization",
                isError: true,
            },
        ]);
        const result = await persistReplayLabels({
            client,
            rawInput: {
                expectedTraceIds: [A],
                verdicts: [{ traceId: A, label: true, annotation: "x" }],
            },
        });
        expect(result.status).toBe("mcp-error");
        if (result.status === "mcp-error") {
            expect(result.idKind).toBe("traceId");
        }
    });
    it("returns mcp-error when an older server reports skipped invalid trace IDs without isError", async () => {
        const client = fakeClient([
            {
                text: `Update complete: set 1 verdict(s). New verdicts appear as suggestions in the labeling UI.\nSkipped (not in this organization): ${B}`,
            },
        ]);
        const result = await persistReplayLabels({
            client,
            rawInput: {
                expectedTraceIds: [A, B],
                verdicts: [
                    { traceId: A, label: true, annotation: "pass" },
                    { traceId: B, label: false, annotation: "fail" },
                ],
            },
        });
        expect(result.status).toBe("mcp-error");
        if (result.status === "mcp-error") {
            expect(result.message).toContain("Skipped (not in this organization)");
            expect(result.partialIds).toEqual([]);
        }
    });
});
describe("persistReplayLabels (input mode disambiguation)", () => {
    it("returns invalid-input when the file matches neither shape", async () => {
        const client = fakeClient([]);
        const result = await persistReplayLabels({
            client,
            rawInput: {
                verdicts: [{ originalTraceId: A, label: true, annotation: "x" }],
            },
        });
        expect(result.status).toBe("invalid-input");
        expect(client.call).not.toHaveBeenCalled();
    });
});
